definition.script:
pipeline {
    agent any
    stages {
        stage('Health Check') {
            steps {
                script {
                    echo "Ejecutando Health Check"
                    final String url = "https://tools-httpstatus.pickup-services.com/200"
                    final String response = bat(script: "@curl -s -L --fail-with-body ${url}", returnStdout: true).trim()
                    echo response
                }
                echo "Health Check ejecutado con éxito!"
                echo "Ejecutando Smoke Tests"
                build job: "Ejemplo cURL en Jenkins"
                echo "Smoke Tests completos: Listos para seguir adelante! "
            }
        }

        stage('Integration Tests') {
            parallel {
                stage('Tests para Endpoint 1') {
                    steps {
                        script {
                            echo "Ejecutando Tests para endpoint 1"
                            final String url = "https://tools-httpstatus.pickup-services.com/200"
                            final String response = bat(script: "@curl -s -L --fail-with-body ${url}", returnStdout: true).trim()
                            echo response
                        }
                    }
                }

                stage('Tests para Endpoint 2') {
                    steps {
                        script {
                            echo "Ejecutando Tests para endpoint 2"
                            final String url = "https://tools-httpstatus.pickup-services.com/200"
                            final String response = bat(script: "@curl -s -L --fail-with-body ${url}", returnStdout: true).trim()
                            echo response
                        }
                    }
                }
            }
        }

        stage("Pruebas de Regresión") {
            parallel {
                stage("Prueba de Regresión Google") {
                    steps {
                        build job: "hola-mundo-node", parameters: [
                            string(name: 'Tag', value: 'Google')
                        ]
                    }
                }

                // Etapa en paralelo para Amazon
                stage("Prueba de Regresión Amazon") {
                    steps {
                        build job: "hola-mundo-node", parameters: [
                            string(name: 'Tag', value: 'Amazon')
                        ]
                    }
                }
            }
        }
    }
}
